import { useState, useEffect } from 'react';
import Navbar from '../components/Navbar';  // Changed from Nav
import image3 from '../assets/image3.jpg';
import imageesport from '../assets/imageesport.jpg';
import imageccs from '../assets/imageccs.jpg';

function AboutPage() {
  const [theme, setTheme] = useState('dark');

  useEffect(() => {
    const savedTheme = localStorage.getItem('theme') || 'dark';
    setTheme(savedTheme);
    document.body.className = savedTheme === 'light' ? 'light-mode' : '';
  }, []);

  const toggleTheme = () => {
    const newTheme = theme === 'dark' ? 'light' : 'dark';
    setTheme(newTheme);
    localStorage.setItem('theme', newTheme);
    document.body.className = newTheme === 'light' ? 'light-mode' : '';
  };

  return (
    <>
      <Navbar theme={theme} toggleTheme={toggleTheme} />
      <main className="container">
        <section className="about-section">
          <h2>What I Love About Gaming</h2>
          <p>
            Gaming allows me to escape into creative worlds, challenge my skills, and connect with other players across the globe.
          </p>
          <img src={image3} alt="Game controller" />
        </section>

        <section className="about-section">
          <h2>My Gaming Journey</h2>
          <p>
            My gaming journey is more than just a series of matches, it is a testament to the teamwork and community built through local competition in La Union. Standing together with our trophies, this photo captures the moment our hard work and shared passion for the game transformed into a sense of regional pride.
          </p>
          <div className="journey-images">
            <img src={imageesport} alt="Esports competition" />
            <img src={imageccs} alt="Gaming setup" />
          </div>
        </section>

        <section className="progression-section">
          <h2>My Gaming Progression</h2>
          <ol>
            <li>Started with casual mobile games.</li>
            <li>Discovered PC and console gaming.</li>
            <li>Joined online multiplayer communities.</li>
            <li>Entered competitive gaming tournaments.</li>
            <li>Explored game streaming and content creation.</li>
            <li>Continually improved skills and strategies.</li>
          </ol>
        </section>

        <section className="about-section">
          <blockquote>
            "Gaming is not just entertainment — it is a way to learn, compete, and grow."
          </blockquote>
        </section>

        <footer>
          <p>Contact: gaming@email.com</p>
          <p>© 2026 Gaming Passion</p>
        </footer>
      </main>
    </>
  );
}

export default AboutPage;
